import React, { useState } from 'react';
import VoiceInput from './VoiceInput';
import './VoiceInputDemo.css';

const VoiceInputDemo = () => {
  const [inputValue, setInputValue] = useState('');
  const [language, setLanguage] = useState('en-US');
  const [results, setResults] = useState([]);

  const handleVoiceResult = (transcript, isFinal) => {
    console.log('Voice result:', transcript, 'Final:', isFinal);
    
    // Update input value in real-time
    setInputValue(transcript);
    
    // Save final results to history
    if (isFinal && transcript.trim()) {
      const newResult = {
        id: Date.now(),
        text: transcript.trim(),
        timestamp: new Date().toLocaleTimeString(),
        language: language
      };
      setResults(prev => [newResult, ...prev.slice(0, 9)]); // Keep last 10 results
    }
  };

  const clearInput = () => {
    setInputValue('');
  };

  const clearHistory = () => {
    setResults([]);
  };

  const languages = [
    { code: 'en-US', name: 'English (US)' },
    { code: 'en-GB', name: 'English (UK)' },
    { code: 'es-ES', name: 'Spanish' },
    { code: 'fr-FR', name: 'French' },
    { code: 'de-DE', name: 'German' },
    { code: 'it-IT', name: 'Italian' },
    { code: 'pt-BR', name: 'Portuguese (Brazil)' },
    { code: 'ja-JP', name: 'Japanese' },
    { code: 'ko-KR', name: 'Korean' },
    { code: 'zh-CN', name: 'Chinese (Mandarin)' },
    { code: 'hi-IN', name: 'Hindi' },
    { code: 'ta-IN', name: 'Tamil' },
    { code: 'ar-SA', name: 'Arabic' },
    { code: 'ru-RU', name: 'Russian' }
  ];

  return (
    <div className="voice-input-demo">
      <div className="demo-header">
        <h2>🎤 Voice Input Demo</h2>
        <p>Test speech-to-text functionality with real-time transcription</p>
      </div>

      <div className="demo-controls">
        <div className="language-selector">
          <label htmlFor="language-select">Language:</label>
          <select 
            id="language-select"
            value={language} 
            onChange={(e) => setLanguage(e.target.value)}
            className="language-dropdown"
          >
            {languages.map(lang => (
              <option key={lang.code} value={lang.code}>
                {lang.name}
              </option>
            ))}
          </select>
        </div>
      </div>

      <div className="demo-content">
        <div className="voice-section">
          <VoiceInput
            onResult={handleVoiceResult}
            language={language}
            placeholder="Your speech will appear here in real-time..."
            continuous={false}
            interimResults={true}
          />
        </div>

        <div className="output-section">
          <div className="current-input">
            <h3>Current Input</h3>
            <div className="input-display">
              <textarea
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                placeholder="Voice input will appear here..."
                rows={3}
                className="input-textarea"
              />
              <button 
                onClick={clearInput}
                className="clear-input-btn"
                disabled={!inputValue}
              >
                Clear Input
              </button>
            </div>
          </div>

          <div className="results-history">
            <div className="history-header">
              <h3>Recognition History</h3>
              {results.length > 0 && (
                <button 
                  onClick={clearHistory}
                  className="clear-history-btn"
                >
                  Clear History
                </button>
              )}
            </div>
            
            {results.length === 0 ? (
              <div className="no-results">
                <p>No voice recognition results yet.</p>
                <p>Start speaking to see your results here!</p>
              </div>
            ) : (
              <div className="results-list">
                {results.map(result => (
                  <div key={result.id} className="result-item">
                    <div className="result-text">{result.text}</div>
                    <div className="result-meta">
                      <span className="result-time">{result.timestamp}</span>
                      <span className="result-lang">{result.language}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="demo-info">
        <h3>How to Use</h3>
        <ol>
          <li><strong>Allow microphone access</strong> when prompted by your browser</li>
          <li><strong>Select your language</strong> from the dropdown above</li>
          <li><strong>Click "Start"</strong> to begin voice recognition</li>
          <li><strong>Speak clearly</strong> into your microphone</li>
          <li><strong>Click "Stop"</strong> when finished, or it will auto-stop after 30 seconds</li>
        </ol>

        <div className="browser-support">
          <h4>Browser Support</h4>
          <ul>
            <li>✅ <strong>Google Chrome</strong> - Full support</li>
            <li>✅ <strong>Microsoft Edge</strong> - Full support</li>
            <li>⚠️ <strong>Firefox</strong> - Limited support</li>
            <li>❌ <strong>Safari</strong> - Not supported</li>
          </ul>
        </div>

        <div className="troubleshooting">
          <h4>Troubleshooting</h4>
          <ul>
            <li><strong>No speech detected:</strong> Check microphone permissions and speak louder</li>
            <li><strong>Poor accuracy:</strong> Speak more clearly and reduce background noise</li>
            <li><strong>Not working:</strong> Try using Google Chrome and ensure microphone access is allowed</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default VoiceInputDemo;
